-- Dasarang Chicken final allergy seed
-- Final menu list separates bone and boneless variants.
begin;

on conflict (slug) do update
set category_id = excluded.category_id, name = excluded.name, official_url = excluded.official_url, allergen_source_url = excluded.allergen_source_url, data_status = excluded.data_status, last_checked_at = excluded.last_checked_at, display_order = excluded.display_order, is_active = true;

on conflict (brand_id, source_type, url) do update
set title = excluded.title, checked_at = excluded.checked_at, note = excluded.note;

update public.menus
set is_active = false
where brand_id = (select id from public.brands where slug = 'dasarang')
  and slug not in ('dasarang-bone-fried', 'dasarang-bone-yangnyeom', 'dasarang-bone-hwasal', 'dasarang-bone-blackbuster', 'dasarang-bone-redmagic', 'dasarang-bone-gangjeong', 'dasarang-boneless-fried', 'dasarang-boneless-yangnyeom', 'dasarang-boneless-hwasal', 'dasarang-boneless-blackbuster', 'dasarang-boneless-redmagic', 'dasarang-boneless-gangjeong', 'dasarang-boneless-chippurin', 'dasarang-boneless-pandora', 'dasarang-boneless-oriental-pa', 'dasarang-boneless-cream-onion', 'dasarang-boneless-tangsuyuk', 'dasarang-boneless-yuringi', 'dasarang-boneless-chili');

on conflict (slug) do update
set brand_id = excluded.brand_id, category_id = excluded.category_id, name = excluded.name, source_url = excluded.source_url, last_checked_at = excluded.last_checked_at, menu_status = excluded.menu_status, is_active = true;

delete from public.menu_allergens
where menu_id in (select id from public.menus where brand_id = (select id from public.brands where slug = 'dasarang'));

;

commit;
